import type { PaginationParams, PaginatedResponse, Order, OrderStatus } from '~/types'

export function useOrdersApi() {
    const { $api } = useNuxtApp()

    return {
        findAll(params?: PaginationParams & { status?: string; paymentStatus?: string; merchantId?: string }) {
            return $api<PaginatedResponse<Order>>('/orders', { params })
        },
        findById(id: string) {
            return $api<Order>(`/orders/${id}`)
        },
        getStats() {
            return $api<any>('/orders/stats')
        },
        updateStatus(id: string, status: OrderStatus) {
            return $api<any>(`/orders/${id}/status`, { method: 'PATCH', body: { status } })
        },
    }
}
